hydro.family100 = hydro.family100 ? hydro.family100 : {}
if (from in hydro.family100 && !m.key.fromMe) {
  let similarity = require('similarity')
  let threshold = 0.72
  let id = m.chat
  let users = global.db.users[m.sender]
  let room = hydro.family100[id]
  let text = budy.toLowerCase().replace(/[^\w\s\-]+/g, '').trim()
  let isSurrender = /^((me)?nyerah|surr?ender)$/i.test(budy)

  if (!isSurrender) {
    let index = room.answer.map(v => String(v).toLowerCase()).indexOf(text)

    if (index < 0) {
      let left = room.answer
        .filter((_, idx) => !room.teranswer[idx])
        .map(v => String(v).toLowerCase())

      if (left.length) {
        let sim = Math.max(...left.map(j => similarity(j, text)))
        if (sim >= threshold) return replyhydro('Dikit again!')
      }
      return
    }

    if (!isCmd && room.teranswer[index]) return

    users.money = Number(users.money || 0) + Number(room.winScore || 0)
    room.teranswer[index] = m.sender
  }

  let isWin = room.teranswer.length === room.teranswer.filter(v => v).length

  const answeredLines = room.answer.map((answer, idx) => {
    if (!isSurrender && !room.teranswer[idx]) return `┃ ${String(idx + 1).padStart(2, '0')}. ❓ *________*`
    const by = room.teranswer[idx]
    const byNum = by ? by.split('@')[0] : ''
    return `┃ ${String(idx + 1).padStart(2, '0')}. ✅ *${answer}*${by ? `  —  @${byNum}` : ''}`
  }).join('\n')

  const mentions = room.teranswer
    .filter(v => typeof v === 'string' && v.endsWith('@s.whatsapp.net'))

  let caption = `
╭━━━〔 🎲 *FAMILY 100* 〕━━━⬣
┃ 🧩 *Question:*
┃ ${room.soal}
┃
┃ ${isWin 
    ? '🏁 *Status:* All answers completed ✅' 
    : isSurrender 
    ? '🏳️ *Status:* Game surrendered ❌' 
    : `🎁 *Reward:* Rp ${Number(room.winScore || 0).toLocaleString('id-ID')} per answer`}
╰━━━━━━━━━━━━━━━━━━⬣

╭━━━〔 📋 *ANSWERS* 〕━━━⬣
${answeredLines}
╰━━━━━━━━━━━━━━━━━━⬣
`.trim()

  hydro.sendMessage(m.chat, { text: caption, mentions }, { quoted: m }).then(msg => {
    hydro.family100[id].msg = msg
  }).catch(_ => _)

  if (isWin || isSurrender) delete hydro.family100[id]
}
