delete this.anonymous[romeo.id]
let room = Object.values(this.anonymous).find(room => room.state === 'WAITING' && !room.check(m.sender))
if (room) {
hydro.sendMessage(room.a, {text: `Success Menemu Partner, sekarang you dapat sending message\n\n${prefix}skip -- _searching partner lain_\n${prefix}stop -- _menghenti sesi chat_`})
room.b = m.sender
room.state = 'CHATTING'
reply(`Success Menemu Partner, sekarang you dapat sending message\n\n${prefix}skip -- _searching partner lain_\n${prefix}stop -- _menghenti sesi chat_`)
} else {
let id = + new Date
this.anonymous[id] = {
id,
a: m.sender,
b: '',
state: 'WAITING',
check: function (who = '') {
return [this.a, this.b].includes(who)
},
other: function (who = '') {
return who === this.a ? this.b : who === this.b ? this.a : ''
},
}
reply(`Mohon Wait Processing Searching Partner`)
}
break
